@startuml
skinparam classAttributeIconSize 0

class "Plataforma" {
    + String designacao
} <<C>> 

class Organizacao {
    - String nome
    - String NIF
    - String website
    - String telefone
    - String email
} <<C>> 

class Colaborador {
    - String nome
    - String funcao
    - String telefone
    - String email
} <<C>> 

class Utilizador {
    - String nome
    - String email
    - String password
} <<C>> 


' Relationships 
Organizacoes --|> Plataforma : tem registadas >  
Colaboradores --> Organizacão : pertence à organização <   
Utilizadors -> colaboradOrs: atua como<  

@enduml
